import React, { useEffect, useState } from "react";
import axios from "axios";
import { Plus, X, Loader } from 'lucide-react'; // Usamos íconos de Lucide para estética

export default function Categorias() {
  // --- Estados de la Aplicación ---
  const [categorias, setCategorias] = useState([]);
  const [productos, setProductos] = useState([]);
  const [categoriaSeleccionada, setCategoriaSeleccionada] = useState(null);
  const [cargando, setCargando] = useState(false);
  
  // --- Estados para el Modal de Nueva Categoría ---
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState("");
  const [newCategoryDescription, setNewCategoryDescription] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");

  useEffect(() => {
    obtenerCategorias();
  }, []);

  // --- Funciones de Fetching ---

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    }
  };

  const mostrarProductosPorCategoria = async (categoria) => {
    setCategoriaSeleccionada(categoria);
    setCargando(true);
    try {
      const res = await axios.get(
        `http://localhost:5000/api/productos/categoria/${categoria.id}`
      );
      setProductos(res.data);
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    } finally {
      setCargando(false);
    }
  };

  const volverACategorias = () => {
    setCategoriaSeleccionada(null);
    setProductos([]);
  };

  // --- Función para Agregar Nueva Categoría ---
  const agregarNuevaCategoria = async (e) => {
    e.preventDefault();
    setErrorMsg("");

    if (!newCategoryName.trim()) {
      setErrorMsg("El nombre de la categoría es obligatorio.");
      return;
    }

    setIsSubmitting(true);
    
    try {
      const nuevaCategoria = {
        nombre: newCategoryName,
        descripcion: newCategoryDescription,
      };

      // Realizar la solicitud POST a la API
      await axios.post("http://localhost:5000/api/categorias", nuevaCategoria);

      // Limpiar y cerrar el modal
      setNewCategoryName("");
      setNewCategoryDescription("");
      setIsModalOpen(false);
      
      // Refrescar la lista de categorías para incluir la nueva
      obtenerCategorias();

    } catch (error) {
      console.error("❌ Error al agregar categoría:", error);
      setErrorMsg("Error al guardar la categoría. Inténtalo de nuevo.");
    } finally {
      setIsSubmitting(false);
    }
  };

  // --- Componente Modal (renderizado condicional) ---
  const NewCategoryModal = () => {
    if (!isModalOpen) return null;

    return (
      <div 
        className="fixed inset-0 bg-gray-600 bg-opacity-75 flex items-center justify-center p-4 z-50 transition-opacity"
        onClick={() => setIsModalOpen(false)} // Cerrar al hacer clic fuera
      >
        <div 
          className="bg-white rounded-xl shadow-2xl w-full max-w-lg p-6 md:p-8 transform transition-all scale-100"
          onClick={(e) => e.stopPropagation()} // Prevenir que se cierre el modal al hacer clic dentro
        >
          <div className="flex justify-between items-start border-b pb-3 mb-4">
            <h3 className="text-2xl font-bold text-gray-900">Crear Nueva Categoría</h3>
            <button 
              onClick={() => setIsModalOpen(false)}
              className="text-gray-400 hover:text-gray-600 transition"
              aria-label="Cerrar modal"
            >
              <X size={24} />
            </button>
          </div>

          <form onSubmit={agregarNuevaCategoria}>
            <div className="mb-4">
              <label htmlFor="nombre" className="block text-sm font-medium text-gray-700 mb-1">
                Nombre de la Categoría <span className="text-red-500">*</span>
              </label>
              <input
                id="nombre"
                type="text"
                value={newCategoryName}
                onChange={(e) => setNewCategoryName(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-blue-500 focus:border-blue-500"
                placeholder="Ej: Electrónica, Ropa, Hogar"
                required
                disabled={isSubmitting}
              />
            </div>
            
            <div className="mb-6">
              <label htmlFor="descripcion" className="block text-sm font-medium text-gray-700 mb-1">
                Descripción (Opcional)
              </label>
              <textarea
                id="descripcion"
                value={newCategoryDescription}
                onChange={(e) => setNewCategoryDescription(e.target.value)}
                rows="3"
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 resize-none"
                placeholder="Una breve descripción de lo que incluye esta categoría."
                disabled={isSubmitting}
              ></textarea>
            </div>

            {errorMsg && (
              <p className="text-red-500 text-sm mb-4 p-2 bg-red-50 rounded-lg border border-red-200">
                {errorMsg}
              </p>
            )}

            <div className="flex justify-end space-x-3">
              <button
                type="button"
                onClick={() => setIsModalOpen(false)}
                className="px-4 py-2 text-sm font-semibold rounded-lg border border-gray-300 text-gray-700 hover:bg-gray-100 transition duration-150"
                disabled={isSubmitting}
              >
                Cancelar
              </button>
              <button
                type="submit"
                className="px-4 py-2 text-sm font-semibold rounded-lg bg-blue-600 text-white hover:bg-blue-700 transition duration-150 flex items-center justify-center disabled:opacity-50"
                disabled={isSubmitting}
              >
                {isSubmitting ? (
                  <>
                    <Loader className="animate-spin mr-2" size={18} />
                    Guardando...
                  </>
                ) : (
                  "Guardar Categoría"
                )}
              </button>
            </div>
          </form>
        </div>
      </div>
    );
  };

  // --- Renderizado Principal ---
  return (
    <div className="p-4 sm:p-8 max-w-7xl mx-auto min-h-screen">
      
      {/* 1. Renderizado de Categorías */}
      {!categoriaSeleccionada ? (
        <>
          <div className="flex flex-col sm:flex-row justify-between items-center mb-8 border-b pb-4">
            <h2 className="text-3xl font-extrabold text-gray-900 mb-4 sm:mb-0">
              Gestión de Categorías
            </h2>
            <button
              onClick={() => setIsModalOpen(true)}
              className="flex items-center px-4 py-2 bg-indigo-600 text-white font-semibold rounded-xl shadow-lg hover:bg-indigo-700 transition duration-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2"
            >
              <Plus size={20} className="mr-2" />
              Agregar Nueva Categoría
            </button>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            {categorias.length > 0 ? (
              categorias.map((cat) => (
                <div key={cat.id} 
                  className="bg-white rounded-xl shadow-lg p-6 border-t-4 border-indigo-500 hover:shadow-xl transition duration-300 transform hover:scale-[1.02] cursor-pointer"
                  onClick={() => mostrarProductosPorCategoria(cat)}
                  aria-label={`Ver productos en la categoría ${cat.nombre}`}
                >
                  <h4 className="text-xl font-bold text-indigo-600 mb-2">
                    {cat.nombre}
                  </h4>
                  <p className="text-gray-500 text-sm overflow-hidden text-ellipsis whitespace-nowrap">
                    {cat.descripcion || "Sin descripción disponible"}
                  </p>
                </div>
              ))
            ) : (
              <p className="text-center text-gray-500 col-span-full py-10">
                Aún no hay categorías registradas. ¡Usa el botón para agregar una!
              </p>
            )}
          </div>
        </>
      ) : (
        /* 2. Renderizado de Productos por Categoría */
        <>
          <div className="flex flex-col sm:flex-row justify-between items-center mb-6 border-b pb-4">
            <h3 className="text-2xl font-bold text-gray-900">
              Productos en “{categoriaSeleccionada.nombre}”
            </h3>
            <button
              className="flex items-center mt-4 sm:mt-0 px-4 py-2 border border-gray-300 text-gray-700 font-semibold rounded-lg hover:bg-gray-50 transition"
              onClick={volverACategorias}
            >
              <span className="mr-2">←</span> Volver a Categorías
            </button>
          </div>

          {cargando ? (
            <div className="flex justify-center items-center py-10 text-indigo-600">
              <Loader className="animate-spin mr-3" size={24} />
              Cargando productos...
            </div>
          ) : productos.length > 0 ? (
            <div className="overflow-x-auto shadow-md rounded-xl">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-800 text-white">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium uppercase tracking-wider rounded-tl-xl">ID</th>
                    <th className="px-6 py-3 text-left text-xs font-medium uppercase tracking-wider">Nombre</th>
                    <th className="px-6 py-3 text-left text-xs font-medium uppercase tracking-wider">Precio</th>
                    <th className="px-6 py-3 text-center text-xs font-medium uppercase tracking-wider rounded-tr-xl">Stock</th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {productos.map((p) => (
                    <tr key={p.id} className="hover:bg-gray-50">
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{p.id}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{p.nombre}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-green-600 font-semibold">${p.precio}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-center text-sm">
                        <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${p.stock > 0 ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                          {p.stock}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <p className="text-center text-gray-500 py-10">
              No hay productos asociados a esta categoría.
            </p>
          )}
        </>
      )}

      {/* 3. Inclusión del Modal */}
      <NewCategoryModal />
    </div>
  );
}
